"use client"

import { useState, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from "@/components/ui/card"
import { useToast } from "@/hooks/use-toast"
import { Spinner } from "@/components/ui/spinner"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"

export default function AdminDashboard() {
  const [isLoading, setIsLoading] = useState(false)
  const [stats, setStats] = useState({ projects: 0, publications: 0, research: 0 })
  const { toast } = useToast()

  // Form State for new project
  const [newProject, setNewProject] = useState({
    title: "",
    shortDescription: "",
    fullDescription: "",
    category: "Deep Learning",
    technologies: "",
    status: "Completed",
    featured: false
  })

  const fetchStats = async () => {
    try {
      const [projRes, pubRes, resRes] = await Promise.all([
        fetch("/api/projects"),
        fetch("/api/publications"),
        fetch("/api/research")
      ])
      const projects = await projRes.json()
      const publications = await pubRes.json()
      const research = await resRes.json()
      
      setStats({
        projects: Array.isArray(projects) ? projects.length : 0,
        publications: Array.isArray(publications) ? publications.length : 0,
        research: Array.isArray(research) ? research.length : 0
      })
    } catch (err) {
      console.error("Failed to fetch stats", err)
    }
  }

  useEffect(() => {
    fetchStats()
  }, [])

  const handleSeedDatabase = async () => {
    if (!confirm("Are you sure? This will delete existing data and insert demo data.")) return
    
    setIsLoading(true)
    try {
      const response = await fetch("/api/admin/seed", { method: "POST" })
      if (response.ok) {
        toast({ title: "Success", description: "Database seeded with demo data!" })
        fetchStats()
      }
    } catch (err) {
      toast({ title: "Error", description: "Failed to seed database.", variant: "destructive" })
    } finally {
      setIsLoading(false)
    }
  }

  const handleClearDatabase = async () => {
    if (!confirm("Are you sure? This will delete ALL data in the database.")) return
    
    setIsLoading(true)
    try {
      // We can use the seed API with a clear flag or a new API
      const response = await fetch("/api/admin/clear", { method: "POST" })
      if (response.ok) {
        toast({ title: "Success", description: "Database cleared!" })
        fetchStats()
      }
    } catch (err) {
      toast({ title: "Error", description: "Failed to clear database.", variant: "destructive" })
    } finally {
      setIsLoading(false)
    }
  }

  const handleAddProject = async (e: React.FormEvent) => {
    e.preventDefault()
    setIsLoading(true)
    try {
      const response = await fetch("/api/projects", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...newProject,
          technologies: newProject.technologies.split(",").map(s => s.trim())
        })
      })
      if (response.ok) {
        toast({ title: "Success", description: "Project added successfully!" })
        setNewProject({
          title: "",
          shortDescription: "",
          fullDescription: "",
          category: "Deep Learning",
          technologies: "",
          status: "Completed",
          featured: false
        })
        fetchStats()
      }
    } catch (err) {
      toast({ title: "Error", description: "Failed to add project.", variant: "destructive" })
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="max-w-4xl mx-auto space-y-12 pb-20">
      <h1 className="text-3xl font-bold">Admin Dashboard</h1>
      
      {/* Stats Section */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <StatCard title="Projects" count={stats.projects} />
        <StatCard title="Papers" count={stats.publications} />
        <StatCard title="Research" count={stats.research} />
      </div>

      {/* Database Management */}
      <Card>
        <CardHeader>
          <CardTitle>Database Management</CardTitle>
          <CardDescription>Control your portfolio content</CardDescription>
        </CardHeader>
        <CardContent className="flex gap-4">
          <Button onClick={handleSeedDatabase} disabled={isLoading} variant="outline">
            {isLoading ? <Spinner className="mr-2" /> : null}
            Reset to Demo Data
          </Button>
          <Button onClick={handleClearDatabase} disabled={isLoading} variant="destructive">
            Clear All Data
          </Button>
        </CardContent>
      </Card>

      {/* Add Project Form */}
      <Card>
        <CardHeader>
          <CardTitle>Add New Project</CardTitle>
          <CardDescription>Enter your project details to show them on the site</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleAddProject} className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="title">Project Title</Label>
                <Input 
                  id="title" 
                  value={newProject.title} 
                  onChange={(e) => setNewProject({...newProject, title: e.target.value})} 
                  required 
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="category">Category</Label>
                <Input 
                  id="category" 
                  value={newProject.category} 
                  onChange={(e) => setNewProject({...newProject, category: e.target.value})} 
                />
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="short">Short Description</Label>
              <Input 
                id="short" 
                value={newProject.shortDescription} 
                onChange={(e) => setNewProject({...newProject, shortDescription: e.target.value})} 
                required 
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="long">Full Description</Label>
              <Textarea 
                id="long" 
                value={newProject.fullDescription} 
                onChange={(e) => setNewProject({...newProject, fullDescription: e.target.value})} 
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="tech">Technologies (comma separated)</Label>
              <Input 
                id="tech" 
                placeholder="React, PyTorch, MongoDB"
                value={newProject.technologies} 
                onChange={(e) => setNewProject({...newProject, technologies: e.target.value})} 
              />
            </div>
            <Button type="submit" disabled={isLoading} className="w-full">
              {isLoading ? <Spinner className="mr-2" /> : null}
              Add Project
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  )
}

function StatCard({ title, count }: { title: string; count: number }) {
  return (
    <Card>
      <CardContent className="pt-6">
        <div className="text-2xl font-bold text-primary">{count}</div>
        <div className="text-sm text-muted-foreground">{title}</div>
      </CardContent>
    </Card>
  )
}
